{
  "name": "Eigenheim Navigator Landingpage",
  "description": "Eine hochkonvertierende Landingpage für Schweizer Immobilien- und Finanzdienstleistungen, optimiert für Lead-Generierung und klare Nutzerführung.",
  "requestFramePermissions": []
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

import React, { useState, useEffect } from 'react';
import Header from './components/Header';
import Hero from './components/Hero';
import RealitySection from './components/RealitySection';
import SolutionSection from './components/SolutionSection';
import SocialProofSection from './components/SocialProofSection';
import ProcessSection from './components/ProcessSection';
import PartnerSection from './components/PartnerSection';
import FAQSection from './components/FAQSection';
import ContactSection from './components/ContactSection';
import Footer from './components/Footer';
import StickyMobileCTA from './components/StickyMobileCTA';

const App: React.FC = () => {
  const [hasScrolled50, setHasScrolled50] = useState(false);

  useEffect(() => {
    const handleScroll = () => {
      const scrollPosition = window.scrollY;
      const totalHeight = document.documentElement.scrollHeight - window.innerHeight;
      if (scrollPosition > totalHeight * 0.5 && !hasScrolled50) {
        console.log('Tracking: scroll_50_percent');
        // In a real app, dispatch to tracking tool here
        setHasScrolled50(true);
      }
    };

    window.addEventListener('scroll', handleScroll);
    return () => window.removeEventListener('scroll', handleScroll);
  }, [hasScrolled50]);

  return (
    <div className="relative min-h-screen flex flex-col">
      <Header />
      <main className="flex-grow">
        <Hero />
        <RealitySection />
        <SolutionSection />
        <SocialProofSection />
        <ProcessSection />
        <PartnerSection />
        <FAQSection />
        <ContactSection />
      </main>
      <Footer />
      <StickyMobileCTA />
    </div>
  );
};

export default App;

