{
  "name": "Eigenheim Navigator Landingpage",
  "description": "Hochkonvertierende Landingpage für Schweizer Immobilien-Finanzierung mit 2-stufigem Realitätscheck.",
  "requestFramePermissions": [
    "geolocation"
  ]
}

import React from 'react';
import { createRoot } from 'react-dom/client';
import App from './App';

const container = document.getElementById('root');
if (container) {
  const root = createRoot(container);
  root.render(<App />);
}

import React, { useState, useEffect } from 'react';
import Header from './components/Header';
import Hero from './components/Hero';
import RealitySection from './components/RealitySection';
import SolutionSection from './components/SolutionSection';
import SocialProofSection from './components/SocialProofSection';
import ProcessSection from './components/ProcessSection';
import PartnerSection from './components/PartnerSection';
import FAQSection from './components/FAQSection';
import ContactSection from './components/ContactSection';
import Footer from './components/Footer';
import StickyMobileCTA from './components/StickyMobileCTA';

const App: React.FC = () => {
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [checkStep, setCheckStep] = useState(1);
  const [formData, setFormData] = useState({
    timeframe: '',
    income: '',
    equity: ''
  });

  const openModal = () => {
    console.log('Tracking: check_modal_open');
    setIsModalOpen(true);
    setCheckStep(1);
    document.body.style.overflow = 'hidden';
  };

  const closeModal = () => {
    console.log('Tracking: check_modal_close');
    setIsModalOpen(false);
    document.body.style.overflow = 'unset';
  };

  const handleStep1Submit = (e: React.FormEvent) => {
    e.preventDefault();
    console.log('Tracking: check_result_view', formData);
    setCheckStep(2);
  };

  // Close on ESC
  useEffect(() => {
    const handleEsc = (event: KeyboardEvent) => {
      if (event.key === 'Escape') closeModal();
    };
    window.addEventListener('keydown', handleEsc);
    return () => window.removeEventListener('keydown', handleEsc);
  }, []);

  return (
    <div className="relative min-h-screen flex flex-col bg-white">
      <Header onStartCheck={openModal} />

      <main className="flex-grow">
        <Hero onStartCheck={openModal} />
        <RealitySection />
        <SolutionSection />
        <SocialProofSection />
        <ProcessSection />
        <PartnerSection />
        <FAQSection />
        <ContactSection />
      </main>

      <Footer />
      <StickyMobileCTA onStartCheck={openModal} />

      {/* REALITÄTSCHECK MODAL */}
      {isModalOpen && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center p-4 sm:p-6">
          {/* Backdrop */}
          <div 
            className="absolute inset-0 bg-slate-900/60 backdrop-blur-sm transition-opacity"
            onClick={closeModal}
          ></div>

          {/* Modal Container */}
          <div className="relative w-full max-w-xl bg-white rounded-[24px] shadow-2xl overflow-hidden animate-fade-in">
            {/* Close Button */}
            <button 
              onClick={closeModal}
              className="absolute top-4 right-4 p-2 text-slate-400 hover:text-slate-600 transition-colors z-10"
              aria-label="Schliessen"
            >
              <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M6 18L18 6M6 6l12 12" />
              </svg>
            </button>

            <div className="p-8 sm:p-10">
              <div className="mb-8">
                <h2 className="text-2xl sm:text-3xl font-extrabold text-slate-900 mb-2">Realitätscheck (90 Sekunden)</h2>
                <p className="text-slate-500 text-sm">3 kurze Fragen – erste Einordnung. Keine Zusage. Keine Verpflichtung.</p>
              </div>

              {checkStep === 1 ? (
                <form onSubmit={handleStep1Submit} className="space-y-6">
                  {/* Q1: Kaufzeitraum */}
                  <div className="space-y-3">
                    <label className="block text-sm font-bold text-slate-700 uppercase tracking-wider text-[11px]">1. Kaufzeitraum</label>
                    <div className="grid grid-cols-3 gap-2">
                      {['0–12 Monate', '1–3 Jahre', '3+ Jahre'].map((t) => (
                        <button
                          key={t}
                          type="button"
                          onClick={() => setFormData({...formData, timeframe: t})}
                          className={`py-3 px-2 rounded-[12px] text-xs font-bold transition-all border-2 ${
                            formData.timeframe === t 
                            ? 'bg-[#2663EB] text-white border-[#2663EB]' 
                            : 'bg-white text-slate-600 border-slate-100 hover:border-[#2663EB]'
                          }`}
                        >
                          {t}
                        </button>
                      ))}
                    </div>
                  </div>

                  {/* Q2: Haushaltseinkommen */}
                  <div className="space-y-3">
